pw.use\(stealth\(\)\);

\(async \(\) => {
  const browser = await pw.launch\({ headless: true, args: ['--no-sandbox'] }\);
  const page = await browser.newPage\(\);
  const apiCalls = [];
  page.on\('response', r => {
    const u = r.url\(\);
    if \(u.includes\('gumtree'\) && \(u.includes\('/api/'\) || u.includes\('search'\) || u.includes\('ads'\)\)\) {
      apiCalls.push\(u\);
    }
  }\);
  await page.goto\('https://www.gumtree.co.za/s-all-the-ads/tracker/k0', { waitUntil: 'domcontentloaded', timeout: 20000 }\);
