  console.log\('Gumtree API calls:'\);
  apiCalls.forEach\(u => console.log\(' ', u\)\);
  if \(!apiCalls.length\) console.log\('None detected — listings may be server-side or CDN-cached'\);
  await browser.close\(\);
}\)\(\).catch\(e => console.error\('Error:', e.message\)\);
